const fs = require('fs');
const path = require('path');
const root = 'backend/src/services';
const files = fs.readdirSync(root).filter(f => f.endsWith('.js')).map(f => path.join(root, f));
const modelCounts = new Map();
for (const file of files) {
  const text = fs.readFileSync(file, 'utf8');
  const regex = /(?:prisma|tx)\\.([a-zA-Z][a-zA-Z0-9_]*)/g;
  let m;
  while ((m = regex.exec(text))) {
    const key = m[1];
    modelCounts.set(key, (modelCounts.get(key) || 0) + 1);
  }
}
console.log(JSON.stringify(Object.fromEntries([...modelCounts.entries()].sort((a,b)=>a[0].localeCompare(b[0]))), null, 2));
