const fs = require('fs');
const path = require('path');
const server = fs.readFileSync('backend/src/server.js','utf8');
const routeRegex = /if \\(req\\.method === \"([A-Z]+)\" && requestUrl\\.pathname === \"(["'^"]+)"'"\\) \\{([\\s\\S]*?)\\n    \\}/g;
const routes=[];
let m;
while((m=routeRegex.exec(server))){
  const [_,method,pathname,body]=m;
  const call = /await\\s+([a-zA-Z0-9_]+)\\(/.exec(body);
  const sendStatic = /sendJson\\(res,\\s*200,\\s*([a-zA-Z0-9_]+)/.exec(body);
  const line = server.slice(0,m.index).split(/\\r?\\n/).length;
  routes.push({method,pathname,line,handler: call?call[1]:(sendStatic?"'`static:${sendStatic[1]}`:'"'')});
}
const startsWithRegex = /if \\(req\\.method === \"([A-Z]+)\" && requestUrl\\.pathname\\.startsWith\\(\"(["'^"]+)"'"\\)\\) \\{([\\s\\S]*?)\\n    \\}/g;
while((m=startsWithRegex.exec(server))){
  const [_,method,pathname,body]=m;
  const line = server.slice(0,m.index).split(/\\r?\\n/).length;
  routes.push({method,pathname:"'`startsWith:${pathname}`,line,handler:'"'sendFile'});
}
console.log(JSON.stringify(routes.sort((a,b)=>a.line-b.line),null,2));
'@ | node -"

