const fs = require('fs');
const path = require('path');
const schema = fs.readFileSync('backend/prisma/schema.prisma','utf8');
const models=[...schema.matchAll(/"'^model'"\\s+(\\w+)/gm)].map(m=>m[1]);
const serviceFiles = fs.readdirSync('backend/src/services').filter(f=>f.endsWith('.js')).map(f=>path.join('backend/src/services',f));
const allFiles=[];
function walk(dir){ for(const entry of fs.readdirSync(dir,{withFileTypes:true})){ if(entry.name==='node_modules') continue; const full=path.join(dir,entry.name); if(entry.isDirectory()) walk(full); else if(entry.name.endsWith('.js')) allFiles.push(full);} }
walk('backend');
function modelToClientName(name){ return name[0].toLowerCase()+name.slice(1); }
const out=[];
for(const model of models){
  const client=modelToClientName(model);
  const serviceHits=[];
  const otherHits=[];
  for(const file of serviceFiles){
    const text=fs.readFileSync(file,'utf8');
    if(new RegExp("'`(?:prisma|tx)'"\\\\."'${client}'"\\\\b"'`).test(text)) serviceHits.push(file.replace(/'"\\\\/g,'/'));
  }
  for(const file of allFiles){
    if(serviceFiles.includes(file)) continue;
    const text=fs.readFileSync(file,'utf8');
    if(new RegExp("'`(?:prisma|tx)'"\\\\."'${client}'"\\\\b"'`).test(text)) otherHits.push(file.replace(/'"\\\\/g,'/'));
  }
  out.push({model,client,serviceHits,otherHits});
}
console.log(JSON.stringify(out,null,2));
'@ | node -"

